function base64Url(input) {
  return Buffer.from(input)
    .toString('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
}

function loadJanusAppDataConfig() {
  const appData = process.env.APPDATA || '';
  const configPath = path.join(appData, 'Janus Projekt', 'config.json');
  return { configPath, config: JSON.parse(fs.readFileSync(configPath, 'utf-8')) };
}

function createE2eJwt() {
  const { configPath, config } = loadJanusAppDataConfig();
  const secret = config.jwt_secret_key;
  if (!secret) throw new Error(`jwt_secret_key missing in ${configPath}`);

  const header = { alg: 'HS256', typ: 'JWT' };
  const payload = {
    sub: 'local_user',
    scopes: ['me', 'settings:write'],
    exp: Math.floor(Date.now() / 1000) + 60 * 60,
  };
  const unsigned = `${base64Url(JSON.stringify(header))}.${base64Url(JSON.stringify(payload))}`;
  const signature = crypto
    .createHmac('sha256', secret)
    .update(unsigned)
    .digest('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
  return `${unsigned}.${signature}`;
}

async function installInternalApiKeyRoute(page, internalKey) {
  if (!internalKey) {
    throw new Error('api_key missing in Janus config.json (required for E2E against real backend)');
  }
  const handler = async (route) => {
    const headers = { ...route.request().headers() };
    headers['X-Janus-Internal-Key'] = internalKey;
    await route.continue({ headers });
  };
  await page.route('http://127.0.0.1:8001/api/**', handler);
  await page.route('http://localhost:8001/api/**', handler);
}

function chatWindow(page, windowName) {
  return page.getByRole('region', { name: `Chat-Fenster ${windowName}` });
}

function chatInput(page, windowName) {
  return chatWindow(page, windowName).getByPlaceholder(/Nachricht an Janus senden/);
}

function assistantResponse(page, windowName) {
  return page.locator(`#chat-messages-${windowName} .message.assistant`).last();
}

function compactApiUrl(url) {
  try {
    const parsed = new URL(url);
    return `${parsed.origin}${parsed.pathname}`;
  } catch {
    return url;
  }
}


function createPromptDiagnostics(page) {
  const events = [];
  const consoleLogs = [];
  const pushEvent = (event) => {
    events.push({ timestamp: new Date().toISOString(), ...event });
    if (events.length > 200) events.shift();
  };
  const pushConsoleLog = (log) => {
    consoleLogs.push({ timestamp: new Date().toISOString(), ...log });
    if (consoleLogs.length > 400) consoleLogs.shift();
  };

  const onRequest = (request) => {
    const url = request.url();
    if (!url.includes('/api/')) return;
    pushEvent({ type: 'request', method: request.method(), url: compactApiUrl(url) });
  };
  const onResponse = (response) => {
    const url = response.url();
    if (!url.includes('/api/')) return;
    pushEvent({ type: 'response', status: response.status(), url: compactApiUrl(url) });
  };
  const onRequestFailed = (request) => {
    const url = request.url();
    if (!url.includes('/api/')) return;
    pushEvent({
      type: 'requestfailed',
      method: request.method(),
      url: compactApiUrl(url),
      failure: request.failure()?.errorText || 'unknown',
    });
  };
  const onConsole = (message) => {
    const text = message.text();
    pushConsoleLog({ type: message.type(), text: text.slice(0, 1000) });
    if (!['error', 'warning'].includes(message.type())) return;
    pushEvent({ type: `console:${message.type()}`, text: text.slice(0, 500) });
  };
  const onPageError = (error) => {
    pushEvent({ type: 'pageerror', text: String(error?.message || error).slice(0, 500) });
  };

  page.on('request', onRequest);
  page.on('response', onResponse);
  page.on('requestfailed', onRequestFailed);
  page.on('console', onConsole);
  page.on('pageerror', onPageError);

  return {
    events,
    consoleLogs,
    dispose() {
      page.off('request', onRequest);
      page.off('response', onResponse);
      page.off('requestfailed', onRequestFailed);
      page.off('console', onConsole);
      page.off('pageerror', onPageError);
    },
  };
}


function writeEvidence(testCaseId, result, classification, evidence, notes) {
  const resultDir = path.join(process.cwd(), 'documentation/test-results/TEST-RUN-2026-05-12-001');
  if (!fs.existsSync(resultDir)) {
    fs.mkdirSync(resultDir, { recursive: true });
  }
  const resultFile = path.join(resultDir, `${testCaseId}_evidence.json`);
  const payload = {
    testRunId: 'TEST-RUN-2026-05-12-001',
    testCaseId,
    result,
    classification,
    prompt: evidence?.prompt || '',
    response: evidence?.response || '',
    networkEvents: evidence?.networkEvents || [],
    consoleErrors: evidence?.consoleErrors || [],
    uiState: evidence?.uiState || {},
    durationMs: evidence?.durationMs || 0,
    strategyVersions: evidence?.strategyVersions || {},
    notes: notes || '',
    timestamp: new Date().toISOString(),
  };
  fs.writeFileSync(resultFile, JSON.stringify(payload, null, 2));
}

function buildEvidence(prompt, responseText, durationMs) {
  return {
    prompt,
    response: responseText || '',
    networkEvents: [],
    consoleErrors: [],
    uiState: {},
    durationMs: durationMs || 0,
    strategyVersions: {
      send: 'chat_window_scoped_send_v1',
      wait: 'assistant_stream_complete_v1',
      evidence: 'capture_network_v1',
      evaluate: 'contains_any_v1',
    },
  };
}


async function runPromptInChatWindow(page, prompt) {
  const diagnostics = createPromptDiagnostics(page);
  const input = chatInput(page, 'A');
  let streamRequestCount = 0;
  let streamRequestUrl = null;

  const onStreamRequest = (request) => {
    const url = request.url();
    if (request.method() === 'POST' && /\/api\/chat\/stream\/?(\?|$)/.test(new URL(url).pathname)) {
      streamRequestCount++;
      streamRequestUrl = url;
    }
  };
  page.on('request', onStreamRequest);

  try {
    // Focus window and ensure input visible
    await chatWindow(page, 'A').click();
    await expect(input).toBeVisible({ timeout: 5000 });

    // SEND STRATEGY: chat_window_scoped_send_v1
    await input.fill(prompt);
    // Submit via real UI interaction (Enter key)
    await input.press('Enter');
    await page.waitForTimeout(300);

    // Patient polling: wait until the assistant bubble holds real content,
    // not just the "..." loading placeholder (which may carry an appended timestamp).
    try {
      await expect(async () => {
        const bubble = page.locator('#chat-messages-A .message.assistant').last();
        await expect(bubble).toBeVisible();
        const text = await bubble.innerText();
        const trimmed = text.trim();
        if (trimmed.startsWith('...')) throw new Error('Still loading');
        expect(trimmed.length).toBeGreaterThan(15);
      }).toPass({ timeout: ASSISTANT_RESPONSE_TIMEOUT_MS });
    } catch (_) {
      throw new Error('RUNNER_STREAM_TIMEOUT: Assistant bubble appeared but is empty or only contains "..." with timestamp. SSE stream observed but no real content rendered.');
    }

    const assistantMessage = assistantResponse(page, 'A');

    // Verify stream request was actually observed (bubble without stream = frontend bug)
    if (streamRequestCount === 0) {
      throw new Error('RUNNER_STREAM_TIMEOUT: Assistant bubble appeared but no POST /api/chat/stream request was observed. Frontend may have rendered static content without backend call.');
    }

    // Check for visible Janus errors
    const errorMessage = page.locator(`#chat-messages-A .message.error, #chat-messages-A .message.system`).last();
    const hasError = await errorMessage.count() > 0;
    if (hasError) {
      const errorText = await errorMessage.textContent();
      throw new Error(`PROVIDER_TIMEOUT: Visible Janus error bubble: ${errorText}`);
    }

    const responseText = await assistantMessage.textContent();
    return responseText || '';
  } catch (error) {
    const apiEvents = diagnostics.events.filter((event) => event.url);
    const chatEvents = apiEvents.filter((event) => /\/api\/.*(chat|message)/i.test(event.url));
    const streamEvents = apiEvents.filter((event) => /\/api\/chat\/stream/i.test(event.url));
    const failedEvents = diagnostics.events.filter(
      (event) => event.type === 'requestfailed' || event.type === 'pageerror' || event.type.startsWith('console:')
    );
    const sendMessageLogs = diagnostics.consoleLogs.filter((log) => log.text.includes('[sendMessage]'));
    const sseLogs = diagnostics.consoleLogs.filter((log) => log.text.includes('[SSE'));

    // DOM diagnostics: capture chat-messages state even when page is still open
    let domDump = 'N/A';
    let messageTexts = 'N/A';
    let domEval = 'N/A';
    try {
      const chatMessagesEl = page.locator(`#chat-messages-${win}`).first();
      domDump = await chatMessagesEl.innerHTML({ timeout: 2000 });
      const msgs = await page.locator(`#chat-messages-${win} .message`).all();
      messageTexts = await Promise.all(msgs.map(async (m) => await m.textContent()));
    } catch (e) { messageTexts = 'ERR: ' + String(e?.message || e).slice(0, 200); }
    try {
      domEval = await page.evaluate((w) => {
        const cm = document.getElementById('chat-messages-' + w);
        if (!cm) return { found: false };
        const messages = Array.from(cm.querySelectorAll('.message')).map((m, i) => ({
          i,
          className: m.className,
          bubbleHTMLLen: m.querySelector('.bubble')?.innerHTML?.length ?? 0,
          bubbleTextLen: m.querySelector('.bubble')?.textContent?.length ?? 0,
          bubbleTextSample: (m.querySelector('.bubble')?.textContent ?? '').slice(0, 80),
          isConnected: m.isConnected,
        }));
        return {
          found: true,
          containerChildCount: cm.childElementCount,
          messageCount: messages.length,
          messages,
          containerHTMLLen: cm.innerHTML.length,
          containerHTMLSample: cm.innerHTML.slice(0, 400),
        };
      }, 'A');
    } catch (e) { domEval = 'EVAL_ERR: ' + String(e?.message || e).slice(0, 200); }

    if (page.isClosed()) {
      throw new Error(
        `RUNNER_WAIT_FAILURE: Playwright page closed before completion for prompt "${prompt}".\nChat Events: ${JSON.stringify(chatEvents)}\nStream Events: ${JSON.stringify(streamEvents)}\nFailures: ${JSON.stringify(failedEvents)}\nOriginal: ${error.message}`
      );
    }

    // Re-throw if already classified — but enrich with SSE diagnostics so we can
    // see where the frontend stream-render pipeline actually broke.
    if (/^(RUNNER_|FRONTEND_|BACKEND_|PROVIDER_|TOOL_|ASSERTION_)/.test(error.message)) {
      throw new Error(`${error.message}
Console [SSE]: ${JSON.stringify(sseLogs)}
DOM eval: ${JSON.stringify(domEval)}
DOM message texts: ${JSON.stringify(messageTexts)}`);
    }

    // Distinguish backend/provider errors from runner errors based on stream observation
    if (streamEvents.length === 0) {
      throw new Error(
        `RUNNER_STREAM_TIMEOUT: No POST /api/chat/stream observed after "${prompt}".
Chat Events: ${JSON.stringify(chatEvents)}
Console [sendMessage]: ${JSON.stringify(sendMessageLogs)}
Console [SSE]: ${JSON.stringify(sseLogs)}
Diagnostics: ${JSON.stringify(diagnostics.events)}
DOM messages: ${JSON.stringify(messageTexts)}
Original: ${error.message}`
      );
    }

    throw new Error(
      `PROVIDER_TIMEOUT: Assistant response not received within ${ASSISTANT_RESPONSE_TIMEOUT_MS}ms after "${prompt}". Stream request was observed but no assistant message rendered.
Chat Events: ${JSON.stringify(chatEvents)}
Stream Events: ${JSON.stringify(streamEvents)}
Failures: ${JSON.stringify(failedEvents)}
Console [SSE]: ${JSON.stringify(sseLogs)}
DOM dump: ${domDump.slice(0, 1200)}
DOM message texts: ${JSON.stringify(messageTexts)}
Original: ${error.message}`
    );
  } finally {
    page.off('request', onStreamRequest);
    diagnostics.dispose();
  }
}

